  specs: PrdSpecs;
  web: string;
  ios: string;
  android: string;
  mini: string;
}

export interface StyleItem {
  id: string;
  title: string;
  tier: 'T0' | 'T1' | 'T2' | 'T3';
  tierColorClass: string;
  description: string;
  application: string;
  // If true, uses a specialized component in InteractiveCards.tsx. 
  // If false/undefined, uses the generic HTML structure defined in constants.tsx
