import { GoogleGenAI, Type } from "@google/genai";
import { StyleItem, FusionResult, ProjectPrd } from "../types";
import { PRD_DATA } from "../constants";

// Initialize Gemini
// NOTE: process.env.API_KEY is handled by the environment as per instructions.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fuseStyles(selectedStyleIds: string[], allStyles: StyleItem[]): Promise<FusionResult> {
  const selectedItems = allStyles.filter(s => selectedStyleIds.includes(s.id));
  const parentNames = selectedItems.map(s => s.title).join(', ');

  // Prepare context data for the AI
  const styleContext = selectedItems.map(item => {
    const prd = PRD_DATA[item.id];
    return {
      name: item.title,
      desc: item.description,
      specs: prd ? prd.specs : {}
    };
  });

  const prompt = `
    Role: World-class UI/UX Designer & Frontend Engineer.
    Task: Create a new, unique UI design style by fusing the following parent styles: ${parentNames}.

    Context Input: ${JSON.stringify(styleContext)}

    Requirements:
    1. **Name**: Invent a creative, catchy name for this new hybrid style (e.g., "Glass-Morphism" + "Pixel" = "Crystal 8-Bit").
    2. **Visual Logic**: Analyze the "DNA" of parent styles (radius, shadow, texture, color) and synthesize them intelligently. Do not just copy-paste; create a true evolution.
    3. **Code**: Generate CSS and HTML to demonstrate a "Card" component in this new style. 
       - The CSS MUST be scoped to a container class named ".fusion-preview-box". 
       - Use CSS variables for colors if possible.
       - The HTML should be a simple, attractive card (e.g., a music player, a credit card, or a profile card) that best shows off the style.
    4. **PRD**: Write brief implementation specs.

    Output Schema (JSON):
    {
      "name": "string",
      "description": "string",
      "css": "string",
      "html": "string",
      "specs": {
        "radius": "string",
        "shadow": "string",
        "font": "string",
        "colors": "string"
      },
      "platform_guides": {
        "web": "string",
        "ios": "string",
        "android": "string",
        "mini": "string"
      }
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            css: { type: Type.STRING },
            html: { type: Type.STRING },
            specs: {
              type: Type.OBJECT,
              properties: {
                radius: { type: Type.STRING },
                shadow: { type: Type.STRING },
                font: { type: Type.STRING },
                colors: { type: Type.STRING },
              },
              required: ["radius", "shadow", "font", "colors"]
            },
            platform_guides: {
              type: Type.OBJECT,
              properties: {
                web: { type: Type.STRING },
                ios: { type: Type.STRING },
                android: { type: Type.STRING },
                mini: { type: Type.STRING },
              },
              required: ["web", "ios", "android", "mini"]
            }
          },
          required: ["name", "description", "css", "html", "specs", "platform_guides"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);

    return {
      id: Date.now().toString(),
      name: data.name,
      description: data.description,
      css: data.css,
      html: data.html,
      parentStyles: selectedItems.map(s => s.title),
      timestamp: Date.now(),
      prd: {
        name: data.name,
        specs: data.specs,
        web: data.platform_guides.web,
        ios: data.platform_guides.ios,
        android: data.platform_guides.android,
        mini: data.platform_guides.mini
      }
    };

  } catch (error) {
    console.error("Fusion failed:", error);
    throw error;
  }
}

// === NEW: Project Genesis Generator ===
export async function generateProjectPrd(userIdea: string, availableStyles: StyleItem[]): Promise<ProjectPrd> {

    // Minimal context to save tokens, just ID and Description
    const stylesContext = availableStyles.map(s => ({ id: s.id, desc: s.description, name: s.title }));

    const prompt = `
    Role: You are a genius CTO, Chief Product Officer, and Design Director wrapped into one.

    User Idea: "${userIdea}"

    Task: 
    1. Analyze the user's idea deeply.
    2. **Visual Strategy**: Select 2-3 UI styles from the provided list that would combine to create the PERFECT aesthetic for this specific idea. Explain the fusion strategy.
    3. **UI Preview**: Generate High-Fidelity HTML and CSS for the *Main Dashboard* or *Hero Section* of this app.
       - FUSE the selected styles visually (e.g., if 'Cyber' and 'Nature', make cyber-plants).
       - The CSS must be scoped to a container class named ".project-preview-box".
       - The HTML must be a functional-looking mock of the interface.
    4. **Product Definition**: Define the Elevator Pitch, Target Audience, and Core Features.
    5. **Tech Stack**: Define a modern, robust tech stack (Frontend, Backend, DB, Infra).
    6. **Architecture**: Design the Database Schema (Entities & Relationships) and key API Endpoints.

    Available Styles: ${JSON.stringify(stylesContext)}

    Constraint: The 'visualStyleFusion.styleIds' must match exactly the 'id' fields from the Available Styles list.

    Output: A complete JSON object for the Project PRD.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING, description: "A cool name for the project" },
                        elevatorPitch: { type: Type.STRING },
                        targetAudience: { type: Type.STRING },
                        visualStyleFusion: {
                            type: Type.OBJECT,
                            properties: {
                                styleIds: { type: Type.ARRAY, items: { type: Type.STRING } },
                                reasoning: { type: Type.STRING },
                                colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } }
                            },
                            required: ["styleIds", "reasoning", "colorPalette"]
                        },
                        previewHtml: { type: Type.STRING, description: "HTML for the dashboard/hero interface" },
                        previewCss: { type: Type.STRING, description: "CSS for the preview, scoped to .project-preview-box" },
                        features: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    name: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    priority: { type: Type.STRING, enum: ["P0", "P1", "P2"] }
                                },
                                required: ["name", "description", "priority"]
                            }
                        },
                        techStack: {
                            type: Type.OBJECT,
                            properties: {
                                frontend: { type: Type.STRING },
                                backend: { type: Type.STRING },
                                database: { type: Type.STRING },
                                infrastructure: { type: Type.STRING }
                            },
                            required: ["frontend", "backend", "database", "infrastructure"]
                        },
                        databaseSchema: { type: Type.STRING, description: "Markdown text describing tables and relationships" },
                        apiEndpoints: { type: Type.STRING, description: "Markdown list of routes" }
                    },
                    required: ["title", "elevatorPitch", "targetAudience", "visualStyleFusion", "previewHtml", "previewCss", "features", "techStack", "databaseSchema", "apiEndpoints"]
                }
            }
        });

        const text = response.text;
        if(!text) throw new Error("AI Generation failed");

        const data = JSON.parse(text);

        return {
            id: Date.now().toString(),
            timestamp: Date.now(),
            userIdea: userIdea,
            ...data
        };

    } catch (e) {
        console.error("Project Generation Failed", e);
        throw e;
    }
}

