import { GoogleGenAI, Type } from "@google/genai";
import { StyleItem, FusionResult, ProjectPrd } from "../types";
import { PRD_DATA } from "../constants";

// Initialize Gemini
// NOTE: process.env.API_KEY is handled by the environment as per instructions.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function fuseStyles(selectedStyleIds: string[], allStyles: StyleItem[]): Promise<FusionResult> {
  const selectedItems = allStyles.filter(s => selectedStyleIds.includes(s.id));
  const parentNames = selectedItems.map(s => s.title).join(', ');

  // Prepare context data for the AI
  const styleContext = selectedItems.map(item => {
    const prd = PRD_DATA[item.id];
    return {
      name: item.title,
      desc: item.description,
      specs: prd ? prd.specs : {}
    };
  });

  const prompt = `
    Role: World-class UI/UX Designer & Frontend Engineer.
    Task: Create a new, unique UI design style by fusing the following parent styles: ${parentNames}.

    Context Input: ${JSON.stringify(styleContext)}

    Requirements:
    1. **Name**: Invent a creative, catchy name for this new hybrid style (e.g., "Glass-Morphism" + "Pixel" = "Crystal 8-Bit").
    2. **Visual Logic**: Analyze the "DNA" of parent styles (radius, shadow, texture, color) and synthesize them intelligently. Do not just copy-paste; create a true evolution.
    3. **Code**: Generate CSS and HTML to demonstrate a "Card" component in this new style. 
       - The CSS MUST be scoped to a container class named ".fusion-preview-box". 
       - Use CSS variables for colors if possible.
       - The HTML should be a simple, attractive card (e.g., a music player, a credit card, or a profile card) that best shows off the style.
    4. **PRD**: Write brief implementation specs.

    Output Schema (JSON):
    {
      "name": "string",
      "description": "string",
      "css": "string",
      "html": "string",
      "specs": {
        "radius": "string",
        "shadow": "string",
        "font": "string",
        "colors": "string"
      },
      "platform_guides": {
        "web": "string",
        "ios": "string",
        "android": "string",
        "mini": "string"
      }
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            description: { type: Type.STRING },
            css: { type: Type.STRING },
            html: { type: Type.STRING },
            specs: {
              type: Type.OBJECT,
              properties: {
                radius: { type: Type.STRING },
                shadow: { type: Type.STRING },
                font: { type: Type.STRING },
                colors: { type: Type.STRING },
              },
              required: ["radius", "shadow", "font", "colors"]
            },
            platform_guides: {
              type: Type.OBJECT,
              properties: {
                web: { type: Type.STRING },
                ios: { type: Type.STRING },
                android: { type: Type.STRING },
                mini: { type: Type.STRING },
              },
              required: ["web", "ios", "android", "mini"]
            }
          },
          required: ["name", "description", "css", "html", "specs", "platform_guides"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);

    return {
      id: Date.now().toString(),
      name: data.name,
      description: data.description,
      css: data.css,
      html: data.html,
      parentStyles: selectedItems.map(s => s.title),
      timestamp: Date.now(),
      prd: {
        name: data.name,
        specs: data.specs,
        web: data.platform_guides.web,
        ios: data.platform_guides.ios,
        android: data.platform_guides.android,
        mini: data.platform_guides.mini
      }
    };

  } catch (error) {
    console.error("Fusion failed:", error);
    throw error;
  }
}

// === GENESIS ENGINE: Full Team Brainstorm ===
export async function generateProjectPrd(userIdea: string, availableStyles: StyleItem[]): Promise<ProjectPrd> {

    // Context for style selection
    const stylesContext = availableStyles.map(s => ({ id: s.id, desc: s.description, name: s.title }));

    const prompt = `
    Role: You are an Elite Digital Product Studio Team comprising:
    1. **Visionary CPO (Chief Product Officer)**: Focuses on user value, market fit, and "wow" factor.
    2. **Genius CTO (Chief Technology Officer)**: Obsessed with scalable architecture, cutting-edge stacks, and security.
    3. **Art Director (UI/UX Lead)**: Master of aesthetics, user psychology, and visual trends.

    User Idea: "${userIdea}"

    Mission:
    Transform this rough idea into a T0-Tier (World Class) Product Specification and a High-Fidelity UI Concept.

    Step 1: The Art Director selects 2-3 visual styles to fuse.
    Step 2: The Art Director writes HTML/CSS for a stunning "Hero Interface" (Dashboard or Landing).
       - **CRITICAL**: The CSS must be scoped to ".project-preview-box".
       - **CRITICAL**: The HTML must be modern, semantic, and visually impressive. Use gradients, shadows, borders, and layout techniques from the selected styles.
    Step 3: The CPO defines the product soul (Elevator Pitch, Features).
    Step 4: The CTO defines the tech backbone (Stack, DB Schema, API).

    Available Styles for Fusion: ${JSON.stringify(stylesContext)}

    Output Format: JSON strictly adhering to the schema.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING, description: "A creative, marketable product name" },
                        elevatorPitch: { type: Type.STRING, description: "A compelling 2-sentence pitch selling the vision" },
                        targetAudience: { type: Type.STRING },
                        visualStyleFusion: {
                            type: Type.OBJECT,
                            properties: {
                                styleIds: { type: Type.ARRAY, items: { type: Type.STRING } },
                                reasoning: { type: Type.STRING, description: "Why these styles? How do they serve the user psychology?" },
                                colorPalette: { type: Type.ARRAY, items: { type: Type.STRING } }
                            },
                            required: ["styleIds", "reasoning", "colorPalette"]
                        },
                        previewHtml: { type: Type.STRING, description: "High-fidelity HTML string for the main UI view" },
                        previewCss: { type: Type.STRING, description: "High-fidelity CSS string, scoped to .project-preview-box" },
                        features: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    name: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    priority: { type: Type.STRING, enum: ["P0", "P1", "P2"] }
                                },
                                required: ["name", "description", "priority"]
                            }
                        },
                        techStack: {
                            type: Type.OBJECT,
                            properties: {
                                frontend: { type: Type.STRING },
                                backend: { type: Type.STRING },
                                database: { type: Type.STRING },
                                infrastructure: { type: Type.STRING }
                            },
                            required: ["frontend", "backend", "database", "infrastructure"]
                        },
                        databaseSchema: { type: Type.STRING, description: "Mermaid.js compatible ERD syntax or Markdown table" },
                        apiEndpoints: { type: Type.STRING, description: "Markdown list of key REST/GraphQL endpoints" }
                    },
                    required: ["title", "elevatorPitch", "targetAudience", "visualStyleFusion", "previewHtml", "previewCss", "features", "techStack", "databaseSchema", "apiEndpoints"]
                }
            }
        });

        const text = response.text;
        if(!text) throw new Error("AI Generation failed");

        const data = JSON.parse(text);

        return {
            id: Date.now().toString(),
            timestamp: Date.now(),
            userIdea: userIdea,
            ...data
        };

    } catch (e) {
        console.error("Project Generation Failed", e);
        throw e;
    }
}

// === GHOST DESIGN TEAM: UI Modifier ===
export async function modifyProjectUi(
    currentHtml: string, 
    currentCss: string, 
    instruction: string,
    selectedElementHtml?: string
): Promise<{ html: string, css: string }> {

    const contextInput = selectedElementHtml 
        ? `User selected this specific element to modify: \n${selectedElementHtml}`
        : `User wants a global modification to the entire view.`;

    const prompt = `
    Role: You are the "Ghost Design Team" - a group of elite UI specialists waiting for feedback.

    Task: Modify the existing HTML/CSS based on the user's specific instruction.

    Current State:
    - HTML: ${currentHtml}
    - CSS: ${currentCss}

    User Instruction: "${instruction}"
    Context: ${contextInput}

    Directives:
    1. **Preserve Structure**: Do not break the existing layout unless asked.
    2. **Apply Changes**: If the user asks to change a color, font, or style of a specific element, apply it precisely.
    3. **Enhance**: If the user instruction is vague (e.g., "Make it pop"), apply professional design principles (shadows, gradients, spacing).
    4. **Scope**: Keep all CSS scoped to ".project-preview-box".
    5. **Output**: Return the FULL updated HTML and CSS.

    Output Schema (JSON):
    {
        "html": "string (full updated html)",
        "css": "string (full updated css)"
    }
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        html: { type: Type.STRING },
                        css: { type: Type.STRING }
                    },
                    required: ["html", "css"]
                }
            }
        });

        const text = response.text;
        if(!text) throw new Error("Modification failed");
        return JSON.parse(text);

    } catch (e) {
        console.error("UI Modification Failed", e);
        throw e;
    }
}

import React, { useEffect, useState, useRef } from 'react';
import { ProjectPrd } from '../types';
import { STYLE_ITEMS } from '../constants';
import { modifyProjectUi } from '../utils/ai';

interface Props {
    project: ProjectPrd;
    onClose: () => void;
    onSave: (p: ProjectPrd) => void;
    isSaved: boolean;
}

const ProjectPrdModal: React.FC<Props> = ({ project, onClose, onSave, isSaved }) => {
    // UI State
    const [visible, setVisible] = useState(false);
    const [activeTab, setActiveTab] = useState<'preview' | 'overview' | 'tech' | 'design'>('preview');

    // Project Data State (Editable)
    const [currentData, setCurrentData] = useState<ProjectPrd>(project);

    // Design Studio State
    const [isEditMode, setIsEditMode] = useState(false);
    const [hoveredElement, setHoveredElement] = useState<HTMLElement | null>(null);
    const [selectedElement, setSelectedElement] = useState<HTMLElement | null>(null);
    const [editPrompt, setEditPrompt] = useState('');
    const [isModifying, setIsModifying] = useState(false);
    const previewContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const timer = setTimeout(() => setVisible(true), 10);
        return () => clearTimeout(timer);
    }, []);

    const handleClose = () => {
        setVisible(false);
        setTimeout(onClose, 200);
    };

    // --- Ghost Team Logic ---

    const handleApplyChanges = async () => {
        if (!editPrompt.trim()) return;

        setIsModifying(true);
        try {
            const result = await modifyProjectUi(
                currentData.previewHtml,
                currentData.previewCss,
                editPrompt,
                selectedElement?.outerHTML
            );

            setCurrentData({
                ...currentData,
                previewHtml: result.html,
                previewCss: result.css
            });

            // Reset selection state
            setEditPrompt('');
            setSelectedElement(null);
            setIsEditMode(false); // Optional: Exit edit mode or stay
        } catch (e) {
            alert("The Ghost Team encountered an error. Please try again.");
        } finally {
            setIsModifying(false);
        }
    };

    // --- Interactive Selection Logic ---

    const handlePreviewMouseOver = (e: React.MouseEvent) => {
        if (!isEditMode) return;
        e.stopPropagation();
        const target = e.target as HTMLElement;
        // Don't select the container itself
        if (target.classList.contains('project-preview-box')) return;
        setHoveredElement(target);
    };

    const handlePreviewMouseOut = () => {
        if (!isEditMode) return;
        setHoveredElement(null);
    };

    const handlePreviewClick = (e: React.MouseEvent) => {
        if (!isEditMode) return;
        e.preventDefault();
        e.stopPropagation();

        const target = e.target as HTMLElement;
        if (target.classList.contains('project-preview-box')) {
            // Deselect if clicking background
            setSelectedElement(null);
            return;
        }

        setSelectedElement(target);
    };

    // Helper to find style details
    const getStyleDetails = (id: string) => STYLE_ITEMS.find(s => s.id === id);

    return (
        <div className="fixed inset-0 bg-black bg-opacity-60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
            <div 
                className={`bg-white w-full max-w-[90vw] h-[90vh] rounded-xl shadow-2xl flex flex-col overflow-hidden transform transition-all duration-300 ${visible ? 'scale-100 opacity-100' : 'scale-95 opacity-0'}`}
            >
                {/* Header */}
                <div className="bg-gray-900 text-white p-5 flex justify-between items-start border-b border-gray-800 flex-shrink-0">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                             <div className="bg-purple-600 text-white text-xs font-bold px-2 py-1 rounded uppercase tracking-wider">Project Genesis Studio</div>
                             <div className="text-gray-400 text-xs font-mono">{new Date(currentData.timestamp).toLocaleDateString()}</div>
                        </div>
                        <h1 className="text-3xl font-bold tracking-tight">{currentData.title}</h1>
                        <p className="text-gray-400 text-sm mt-1 max-w-2xl">Idea: "{currentData.userIdea}"</p>
                    </div>
                    <div className="flex gap-3">
                         <button 
                            onClick={() => onSave(currentData)}
                            disabled={isSaved}
                            className={`px-4 py-2 rounded font-bold text-sm transition ${isSaved ? 'bg-green-600 text-white cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}
                        >
                           {isSaved ? '✓ Saved' : '💾 Save Project'}
                        </button>
                        <button onClick={handleClose} className="text-gray-400 hover:text-white p-2">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                        </button>
                    </div>
                </div>

                {/* Tabs */}
                <div className="bg-gray-100 border-b border-gray-200 flex px-6 space-x-6 flex-shrink-0">
                    {(['preview', 'overview', 'design', 'tech'] as const).map(tab => (
                        <button 
                            key={tab}
                            onClick={() => setActiveTab(tab)}
                            className={`py-4 text-sm font-bold border-b-2 transition capitalize ${activeTab === tab ? 'border-purple-600 text-purple-700' : 'border-transparent text-gray-500 hover:text-gray-800'}`}
