export async function generateProjectPrd(userIdea: string, availableStyles: StyleItem[]): Promise<ProjectPrd> {

    const stylesContext = availableStyles.map(s => ({ id: s.id, desc: s.description, name: s.title }));

    const prompt = `
    You are simulating a high-stakes product strategy meeting between three world-class experts.

    **The Idea**: "${userIdea}"

    **The Team**:
    1. **CPO (Steve)**: Visionary, obsessed with user psychology and "The Why". Hates boring features.
    2. **CTO (Linus)**: Pragmatic, obsessed with performance, security, and scalability. Hates bloat.
    3. **Design Director (Jony)**: Obsessed with aesthetics, emotion, and pixel perfection. Hates ugly UI.

    **Task**:
    1. **Brainstorm**: The team MUST discuss/debate the idea. The CTO might reject a feature because it's too heavy; the CPO might insist on it. The Designer picks the perfect style fusion.
    2. **Decide**: Finalize the Product Spec, Tech Stack, and Visual Direction.
    3. **Build**: Generate the actual HTML/CSS for the "Hero Interface".

    **Available Styles**: ${JSON.stringify(stylesContext)}

    **Output Constraints**:
    - **previewCss**: MUST be scoped to \`.project-preview-box\`. Use advanced CSS (grids, glassmorphism, gradients) suitable for a T0-tier app.
    - **previewHtml**: Must be a semantic, rich mock-up of the main dashboard or landing view.

    Output Schema (JSON):
    {
      "title": "Project Name",
      "elevatorPitch": "2 sentences that sell the dream.",
      "targetAudience": "Specific user persona.",
      "teamBrainstorming": [
         { 
           "role": "CPO", "name": "Steve", "avatar": "👓", 
           "focus": "Market Fit", 
           "opinion": "Critique the idea from a product perspective. Be sharp." 
         },
         { 
           "role": "CTO", "name": "Linus", "avatar": "🐧", 
           "focus": "Scalability", 
           "opinion": "Critique from a tech perspective. Propose a stack." 
         },
         { 
           "role": "Design Director", "name": "Jony", "avatar": "🎨", 
           "focus": "Aesthetics", 
           "opinion": "Propose the visual fusion and explain why these styles match the emotion." 
         }
      ],
      "visualStyleFusion": {
        "styleIds": ["style1", "style2"], 
        "reasoning": "Deep design rationale.",
        "colorPalette": ["#hex", "#hex", "#hex"]
      },
      "previewHtml": "HTML string",
      "previewCss": "CSS string",
      "features": [ { "name": "Feature", "description": "Desc", "priority": "P0" } ],
      "techStack": { "frontend": "Stack", "backend": "Stack", "database": "Stack", "infrastructure": "Stack" },
      "databaseSchema": "Mermaid ERD or Markdown description",
      "apiEndpoints": "Markdown list"
    }
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
            }
        });

        const text = response.text;
        if(!text) throw new Error("AI Generation failed");

        const data = JSON.parse(text);

        return {
            id: Date.now().toString(),
            timestamp: Date.now(),
            userIdea: userIdea,
            ...data
        };

    } catch (e) {
        console.error("Project Generation Failed", e);
        throw e;
    }
}

// === GHOST DESIGN TEAM: LIVE EDIT ===
export async function modifyProjectUi(
    currentHtml: string, 
    currentCss: string, 
    instruction: string,
    selectedElementHtml?: string
): Promise<{ html: string, css: string }> {

    const contextInput = selectedElementHtml 
        ? `The user is pointing specifically at this element: \n${selectedElementHtml}`
        : `The user wants a global change to the entire view.`;

    const prompt = `
    Role: You are the "Ghost Design Team" - an elite UI squad making live adjustments.

    Current UI State:
    - HTML: ${currentHtml}
    - CSS: ${currentCss}

    User Feedback: "${instruction}"
    Context: ${contextInput}

    **Mission**:
    1. **Interpret**: The user might say "Make it pop" -> You interpret this as "Add box-shadows and increase contrast".
    2. **Execute**: Modify the HTML/CSS to reflect the feedback. 
    3. **Refine**: Ensure the design remains consistent and professional.
    4. **Safety**: Keep all CSS scoped to \`.project-preview-box\`.

    Output JSON: { "html": "updated html", "css": "updated css" }
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
            config: { responseMimeType: "application/json" }
        });

        const text = response.text;
        if(!text) throw new Error("Modification failed");
        return JSON.parse(text);

    } catch (e) {
        console.error("UI Modification Failed", e);
        throw e;
    }
}

import React, { useEffect, useState, useRef } from 'react';
import { ProjectPrd } from '../types';
import { STYLE_ITEMS } from '../constants';
import { modifyProjectUi } from '../utils/ai';

interface Props {
    project: ProjectPrd;
    onClose: () => void;
    onSave: (p: ProjectPrd) => void;
    isSaved: boolean;
}

const ProjectPrdModal: React.FC<Props> = ({ project, onClose, onSave, isSaved }) => {
    const [visible, setVisible] = useState(false);
    const [activeTab, setActiveTab] = useState<'overview' | 'preview' | 'tech'>('overview');

    const [currentData, setCurrentData] = useState<ProjectPrd>(project);

    // Design Studio State
    const [isEditMode, setIsEditMode] = useState(false);
    const [selectedElement, setSelectedElement] = useState<HTMLElement | null>(null);
    const [editPrompt, setEditPrompt] = useState('');
    const [isModifying, setIsModifying] = useState(false);
    const previewContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const timer = setTimeout(() => setVisible(true), 10);
        return () => clearTimeout(timer);
    }, []);

    const handleClose = () => {
        setVisible(false);
        setTimeout(onClose, 200);
    };

    // --- Ghost Team Apply Logic ---
    const handleApplyChanges = async () => {
        if (!editPrompt.trim()) return;
        setIsModifying(true);
        try {
            const result = await modifyProjectUi(
                currentData.previewHtml,
                currentData.previewCss,
                editPrompt,
                selectedElement?.outerHTML
            );
            setCurrentData({ ...currentData, previewHtml: result.html, previewCss: result.css });
            setEditPrompt('');
            setSelectedElement(null);
        } catch (e) {
            alert("Design team is busy. Try again.");
        } finally {
            setIsModifying(false);
        }
    };

    // --- Interaction Logic ---
    const handlePreviewClick = (e: React.MouseEvent) => {
        if (!isEditMode) return;
        e.preventDefault();
        e.stopPropagation();
        const target = e.target as HTMLElement;
        if (target.classList.contains('project-preview-box')) {
            setSelectedElement(null);
            return;
        }
        setSelectedElement(target);
    };

    const getStyleDetails = (id: string) => STYLE_ITEMS.find(s => s.id === id);

    return (
        <div className="fixed inset-0 bg-black bg-opacity-70 z-[100] flex items-center justify-center p-4 backdrop-blur-md">
            <div 
                className={`bg-white w-full max-w-[95vw] h-[92vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden transform transition-all duration-300 ${visible ? 'scale-100 opacity-100' : 'scale-95 opacity-0'}`}
            >
                {/* Header */}
                <div className="bg-gray-900 text-white p-6 flex justify-between items-start border-b border-gray-800 flex-shrink-0">
                    <div>
                        <div className="flex items-center gap-3 mb-2">
                             <div className="bg-gradient-to-r from-purple-500 to-pink-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">Project Genesis</div>
                             <div className="text-gray-500 text-xs font-mono">{new Date(currentData.timestamp).toLocaleDateString()}</div>
                        </div>
                        <h1 className="text-3xl font-black tracking-tighter">{currentData.title}</h1>
                    </div>
                    <div className="flex gap-3">
                         <button 
                            onClick={() => onSave(currentData)}
                            disabled={isSaved}
                            className={`px-5 py-2 rounded-full font-bold text-sm transition flex items-center gap-2 ${isSaved ? 'bg-green-600 text-white' : 'bg-white text-black hover:bg-gray-200'}`}
                        >
                           {isSaved ? '✓ Saved' : '💾 Save to Collection'}
                        </button>
                        <button onClick={handleClose} className="text-gray-400 hover:text-white p-2 rounded-full hover:bg-white/10 transition">
                            ✕
                        </button>
                    </div>
                </div>

