                            生成完整 PRD
                        </button>
                    </div>
                </div>
            )}

            {/* Modals */}
            {activeModalId && (
                <PrdModal 
                    id={activeModalId} 
                    onClose={() => setActiveModalId(null)} 
                />
            )}

            {fusionResult && (
                <FusionResultModal 
                    result={fusionResult}
                    isSaved={!!savedFusions.find(f => f.id === fusionResult.id)}
                    onSave={saveFusion}
                    onClose={() => setFusionResult(null)}
