            )}

            {projectResult && (
                <ProjectPrdModal
                    project={projectResult}
                    isSaved={!!savedProjects.find(p => p.id === projectResult.id)}
                    onSave={saveProject}
                    onClose={() => setProjectResult(null)}
                />
            )}
        </div>
    );
};

